import React, { useState } from "react";
import "./Gallery.css";

function Gallery({ cart, setCart }) {
  const [selectedArtist, setSelectedArtist] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 4; // nombre d'œuvres par page

  // artistes et œuvres
  const artists = {
    julien: {
      name: "Julien FAURE",
      image: "images1/photoju.jpg",
      description:
        "Julien dessine depuis son enfance. C'est sa première passion. Il est autodidacte et manie les différentes techniques du dessin.",
      artworks: [
        { title: "Einstein tirant la langue", price: 80, img: "images1/image0.jpeg" },
        { title: "Grenoble vu de la Bastille en couleurs", price: 80, img: "images1/image1.jpeg" },
        { title: "La tour Perret à Grenoble", price: 80, img: "images1/image2.jpeg" },
        { title: "L'arbre de Julien", price: 80, img: "images1/image3.jpeg" },
        { title: "Belledonne vu de Grenoble", price: 80, img: "images1/image4.jpeg" },
        { title: "La dent de Crolles vu de Grenoble", price: 80, img: "images1/image5.jpeg" },
        { title: "Grenoble au stylo noir", price: 80, img: "images1/image6.jpeg" },
        { title: "Portrait au crayon noir", price: 80, img: "images1/image7.jpeg" },
        { title: "Clint Eastwood en train de tirer", price: 80, img: "images1/image8.jpeg" },
      ],
    },
    artiste2: {
      name: "Artiste 2",
      image: "https://via.placeholder.com/200",
      description: "Description de l'artiste 2.",
      artworks: [
        { title: "Œuvre A", price: 120, img: "https://via.placeholder.com/200" },
        { title: "Œuvre B", price: 150, img: "https://via.placeholder.com/200" },
      ],
    },
  };

  const artist = artists[selectedArtist];

  const addToCart = (artwork) => {
    setCart([...cart, artwork]);
  };

  // Pagination
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentArtworks = artist
    ? artist.artworks.slice(indexOfFirstItem, indexOfLastItem)
    : [];

  const totalPages = artist ? Math.ceil(artist.artworks.length / itemsPerPage) : 0;

  return (
    <div className="container">
      <h1>Nos Artistes</h1>

      {/* Sélection artiste */}
      <select
        value={selectedArtist}
        onChange={(e) => {
          setSelectedArtist(e.target.value);
          setCurrentPage(1); // reset page quand on change d'artiste
        }}
      >
        <option value="">Sélectionnez un artiste</option>
        <option value="julien">Julien FAURE</option>
        <option value="artiste2">Artiste 2</option>
      </select>

      {/* Infos artiste */}
      {artist && (
        <div className="artist-info" style={{ display: "block" }}>
          <h2>{artist.name}</h2>
          <img src={artist.image} alt={artist.name} />
          <p>{artist.description}</p>
        </div>
      )}

      {/* Œuvres avec pagination */}
      <div className="artwork">
        {currentArtworks.map((art, index) => (
          <div key={index} className="art-item">
            <h3>{art.title}</h3>
            <img src={art.img} alt={art.title} />
            <p>Prix : {art.price} €</p>
            <button onClick={() => addToCart(art)}>Ajouter au panier</button>
          </div>
        ))}
      </div>

      {/* Pagination */}
      {artist && totalPages > 1 && (
        <ul className="pagination">
          {Array.from({ length: totalPages }, (_, i) => (
            <li
              key={i + 1}
              className={currentPage === i + 1 ? "active" : ""}
            >
              <button onClick={() => setCurrentPage(i + 1)}>{i + 1}</button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default Gallery;
